VALUES
  ('immigration-1aab856d-moex-00300', 'immigration-1aab856d', 'immigration-1aab856d-moex-113-3082b5f1', 'sub-immigration-1aab856d-05', NULL, 'single_choice', '關於法律之適用順序，下列敘述何者正確？', '["行政執行，依行政執行法之規定；行政執行法未規定者，適用其他法律之規定", "行政機關為行政行為時，依行政程序法之規定；行政程序法未規定者，適用其他法律之 規定", "違反行政法上義務而受罰鍰、沒入或其他種類行政罰之處罰時，依行政罰法之規定；行政 罰法未規定者，適用其他法律之規定", "國家損害賠償，國家賠償法以外法律有特別規定者，適用其他法律之規定"]'::jsonb, 0, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:27:54+00:00", "source_pdf_sha1": "a6df21ef30c3", "answer_pdf_sha1": "1b0360af8148", "source_family": "moex-gov-tw", "moex": {"exam_code": "113060", "c": "801", "s": "0404", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "行政法", "year": "113", "exam_name": "113年公務人員特種考試警察人員考試、一般警察人員考試、國家安全情報人員考試、移民行政人員考試", "original_question_number": 18, "answer_corrected": false, "flags": [], "civil_slug": "immigration", "civil_category": "移民行政"}'::jsonb, NULL),
  ('immigration-1aab856d-moex-00301', 'immigration-1aab856d', 'immigration-1aab856d-moex-113-3082b5f1', 'sub-immigration-1aab856d-05', NULL, 'single_choice', '關於資訊公開與閱覽卷宗之敘述，下列何者錯誤？', '["政府資訊公開法與檔案法所規定者，為行政機關之一般性政府資訊公開，與個別行政程序 是否進行中無關", "當事人或利害關係人於行政程序進行中，遭行政機關拒絕閱覽卷宗後，應即向其上級機關 提起訴願", "在一個具體行政程序中，行政機關實施行政指導之相對人，為維護其法律上利益之必要， 依法亦得向該機關請求閱覽卷宗", "政府機關作成決定前，內部單位之擬稿或其他準備作業之文件，如公開對於公益乃屬必要 時，行政機關不得拒絕公開或提供之"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:27:54+00:00", "source_pdf_sha1": "a6df21ef30c3", "answer_pdf_sha1": "1b0360af8148", "source_family": "moex-gov-tw", "moex": {"exam_code": "113060", "c": "801", "s": "0404", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "行政法", "year": "113", "exam_name": "113年公務人員特種考試警察人員考試、一般警察人員考試、國家安全情報人員考試、移民行政人員考試", "original_question_number": 19, "answer_corrected": false, "flags": [], "civil_slug": "immigration", "civil_category": "移民行政"}'::jsonb, NULL),
  ('immigration-1aab856d-moex-00302', 'immigration-1aab856d', 'immigration-1aab856d-moex-113-3082b5f1', 'sub-immigration-1aab856d-05', NULL, 'single_choice', '依行政實務見解，人民對於具行政處分性質之執行命令不服，於聲明異議被駁回後，應如何 為後續之行政爭訟？', '["向為執行命令之機關提起訴願", "向法務部行政執行署提起訴願", "向法務部提起訴願", "逕向行政法院提起行政訴訟"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:27:54+00:00", "source_pdf_sha1": "a6df21ef30c3", "answer_pdf_sha1": "1b0360af8148", "source_family": "moex-gov-tw", "moex": {"exam_code": "113060", "c": "801", "s": "0404", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "行政法", "year": "113", "exam_name": "113年公務人員特種考試警察人員考試、一般警察人員考試、國家安全情報人員考試、移民行政人員考試", "original_question_number": 20, "answer_corrected": false, "flags": [], "civil_slug": "immigration", "civil_category": "移民行政"}'::jsonb, NULL),
  ('immigration-1aab856d-moex-00303', 'immigration-1aab856d', 'immigration-1aab856d-moex-113-3082b5f1', 'sub-immigration-1aab856d-05', NULL, 'single_choice', '甲公司受衛生福利部委託抽驗市面上產品是否符合許可內容，如有不符合者，甲公司並得廢 止其許可。某進口商收到甲公司通知其產品許可自即日起廢止之決定，在訴願及行政訴訟程 序，應如何進行救濟？', '["向衛生福利部之上級機關提起訴願；行政訴訟以衛生福利部為被告", "向衛生福利部提起訴願；行政訴訟以甲公司為被告", "得選擇向衛生福利部或其上級機關提起訴願；行政訴訟應配合前述選擇決定被告為何", "向衛生福利部之上級機關提起訴願；行政訴訟以甲公司為被告"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:27:54+00:00", "source_pdf_sha1": "a6df21ef30c3", "answer_pdf_sha1": "1b0360af8148", "source_family": "moex-gov-tw", "moex": {"exam_code": "113060", "c": "801", "s": "0404", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "行政法", "year": "113", "exam_name": "113年公務人員特種考試警察人員考試、一般警察人員考試、國家安全情報人員考試、移民行政人員考試", "original_question_number": 21, "answer_corrected": false, "flags": [], "civil_slug": "immigration", "civil_category": "移民行政"}'::jsonb, NULL),
  ('immigration-1aab856d-moex-00304', 'immigration-1aab856d', 'immigration-1aab856d-moex-113-3082b5f1', 'sub-immigration-1aab856d-05', NULL, 'single_choice', '甲之土地座落於為都市計畫個別變更範圍之外，遭其鄰人乙無理由侵占，並於其土地上建屋 使用多年，下列敘述何者正確？', '["甲如因都市計畫之個別變更，導致其權利受有侵害，應許其提起行政訴訟以資救濟", "甲依民法請求乙拆屋還地，其攻擊防禦方法如涉公法關係，訴訟應由行政法院審判", "甲應先向普通法院提訴主張拆屋還地，始能對該都市計畫之個別變更提起行政訴訟", "都市計畫個別變更之性質雖屬法規命令，但大法官解釋已承認得對之提起行政訴訟"]'::jsonb, 0, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:27:54+00:00", "source_pdf_sha1": "a6df21ef30c3", "answer_pdf_sha1": "1b0360af8148", "source_family": "moex-gov-tw", "moex": {"exam_code": "113060", "c": "801", "s": "0404", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "行政法", "year": "113", "exam_name": "113年公務人員特種考試警察人員考試、一般警察人員考試、國家安全情報人員考試、移民行政人員考試", "original_question_number": 22, "answer_corrected": false, "flags": [], "civil_slug": "immigration", "civil_category": "移民行政"}'::jsonb, NULL),
  ('immigration-1aab856d-moex-00305', 'immigration-1aab856d', 'immigration-1aab856d-moex-113-3082b5f1', 'sub-immigration-1aab856d-05', NULL, 'single_choice', '關於行政訴訟之訴訟代理人，下列敘述何者正確？', '["訴訟代理人不得委任複代理人", "當事人得委任代理人為訴訟行為；每一當事人委任之訴訟代理人，以1人為限", "交通裁決事件，原告為自然人時，其配偶、三親等內之姻親，雖非律師亦得為訴訟代理人", "高等行政法院管轄之通常訴訟程序上訴事件，當事人原則上應委任律師為訴訟代理人"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:27:54+00:00", "source_pdf_sha1": "a6df21ef30c3", "answer_pdf_sha1": "1b0360af8148", "source_family": "moex-gov-tw", "moex": {"exam_code": "113060", "c": "801", "s": "0404", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "行政法", "year": "113", "exam_name": "113年公務人員特種考試警察人員考試、一般警察人員考試、國家安全情報人員考試、移民行政人員考試", "original_question_number": 23, "answer_corrected": false, "flags": [], "civil_slug": "immigration", "civil_category": "移民行政"}'::jsonb, NULL),
  ('immigration-1aab856d-moex-00306', 'immigration-1aab856d', 'immigration-1aab856d-moex-113-3082b5f1', 'sub-immigration-1aab856d-05', NULL, 'single_choice', '關於國家賠償法之敘述，下列何者錯誤？', '["自然公物經管理機關為適當之警告，人民仍從事冒險活動，致身體受損害時，管理機關得 減輕或免除賠償責任", "於因人力所無從抵抗之自然力介入，造成公共設施未具通常應有之使用狀態，仍須客觀上 國家無法及時修護或採應變且必要之具體措施時，始得免責", "公共設施之設置或管理有欠缺，因而致生損害人民之人身自由時，國家應負賠償責任", "國家賠償法第3條第1項規定係採無過失責任主義"]'::jsonb, 0, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:27:54+00:00", "source_pdf_sha1": "a6df21ef30c3", "answer_pdf_sha1": "1b0360af8148", "source_family": "moex-gov-tw", "moex": {"exam_code": "113060", "c": "801", "s": "0404", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "行政法", "year": "113", "exam_name": "113年公務人員特種考試警察人員考試、一般警察人員考試、國家安全情報人員考試、移民行政人員考試", "original_question_number": 24, "answer_corrected": false, "flags": [], "civil_slug": "immigration", "civil_category": "移民行政"}'::jsonb, NULL),
  ('immigration-1aab856d-moex-00307', 'immigration-1aab856d', 'immigration-1aab856d-moex-113-3082b5f1', 'sub-immigration-1aab856d-05', NULL, 'single_choice', '關於行政損失補償之敘述，下列何者錯誤？', '["人民因可歸責於自己之事由，於執行機關依法實施即時強制，致其生命、身體、財產或自 由遭受特別損失時，仍得請求補償", "行政契約因締約機關所屬公法人之其他機關於契約關係外行使公權力，致相對人履行契約 義務時顯增費用者，相對人得向締約機關請求補償其損失", "行政機關為防止對公益之重大危害，得於必要範圍內調整行政契約內容，並補償相對人因 此所受之財產上損失", "授予利益之違法行政處分經撤銷後，受益人無信賴不值得保護之情形，其因信賴該處分致 遭受財產上之損失者，為撤銷之機關應給予合理之補償"]'::jsonb, 0, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:27:54+00:00", "source_pdf_sha1": "a6df21ef30c3", "answer_pdf_sha1": "1b0360af8148", "source_family": "moex-gov-tw", "moex": {"exam_code": "113060", "c": "801", "s": "0404", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "行政法", "year": "113", "exam_name": "113年公務人員特種考試警察人員考試、一般警察人員考試、國家安全情報人員考試、移民行政人員考試", "original_question_number": 25, "answer_corrected": false, "flags": [], "civil_slug": "immigration", "civil_category": "移民行政"}'::jsonb, NULL),
  ('immigration-1aab856d-moex-00308', 'immigration-1aab856d', 'immigration-1aab856d-moex-111-0e6322b2', 'sub-immigration-1aab856d-01', NULL, 'essay', '關鍵基礎設施韌力（Critical Infrastructure Resilience），做為國土安全重要
